#!/bin/bash
# ============================================================================
# FIX_PROXY.sh - Patch tiktok.py + Active proxy Webshare + Restart Docker
# A coller integralement dans le BROWSER TERMINAL Hostinger (clic droit / Coller)
# ============================================================================

set -e
cd /opt/clip-scraper

echo ""
echo "============================================================"
echo "  FIX PROXY - debut"
echo "============================================================"

# --- 1. Reecrire .env avec PROXY_URL active --------------------------------
printf 'API_KEYS=cd-prod-ac29858a696cf2c1a642dd1c9f607628fcd8b0878cc3c704\nCACHE_TTL_SECONDS=1800\nRATE_LIMIT_PER_HOUR=5000\nPROXY_URL=http://ffcyyfgz:117hrzmrq90n@31.98.15.221:5398\nYOUTUBE_API_KEY=\nINSTAGRAM_SESSION_ID=\nPORT=8001\nMAX_CONCURRENT_SCRAPES=4\n' > /opt/clip-scraper/.env
echo "[OK] .env reecrit"

# --- 2. Patch tiktok.py (base64 = passe le browser terminal sans casser) ---
B64=''
echo "$B64" | base64 -d > /opt/clip-scraper/scrapers/tiktok.py
echo "[OK] tiktok.py patche (taille: $(wc -c < /opt/clip-scraper/scrapers/tiktok.py) octets)"

# --- 3. Test que le proxy Webshare repond -----------------------------------
echo ""
echo "[TEST 1/3] Webshare proxy (devrait retourner une IP francaise)"
PROXY_IP=$(curl -x http://ffcyyfgz:117hrzmrq90n@31.98.15.221:5398 -s --max-time 15 https://ipv4.webshare.io/ 2>&1 || echo "PROXY_KO")
echo "  -> IP retournee : $PROXY_IP"

# --- 4. Down + up Docker (force le rechargement du .env) -------------------
echo ""
echo "[..] Docker compose down + up (force rechargement env_file)..."
docker compose down 2>&1 | tail -5
docker compose up -d 2>&1 | tail -5
echo "[..] Attente 35s pour le startup complet..."
sleep 35

# --- 5. Verifier que le container voit bien PROXY_URL ----------------------
echo ""
echo "[TEST 2/3] Variables d'env vues par le container :"
docker exec clip-scraper env | grep -E "PROXY|API_KEYS" || echo "  ATTENTION: PROXY_URL absent du container !"

# --- 6. Healthcheck (devrait dire proxy:configured) ------------------------
echo ""
echo "[TEST 3/3] Healthcheck (cherche proxy:configured) :"
curl -s http://localhost:8001/health
echo ""

# --- 7. Test scrape TikTok via le scraper ---------------------------------
echo ""
echo "[TEST FINAL] Scrape TikTok via l'API du scraper (timeout 120s)..."
RESULT=$(curl -s -X POST "http://localhost:8001/v1/tiktok/khaby.lame?max_videos=3" \
  -H "X-API-Key: cd-prod-ac29858a696cf2c1a642dd1c9f607628fcd8b0878cc3c704" \
  --max-time 120)
echo "$RESULT" | head -c 1200
echo ""

# --- 8. Logs des dernieres operations -------------------------------------
echo ""
echo "[LOGS] Dernieres lignes du scraper :"
docker logs clip-scraper --tail 15 2>&1

echo ""
echo "============================================================"
echo "  FIX PROXY - termine"
echo "============================================================"
echo ""
echo "Si le test final renvoie un JSON avec videos : SCRAPING TIKTOK OK"
echo "Si erreur : copier-coller toute la sortie ci-dessus dans le chat"
